```class Solution {
public:
    int calculate(string s) {
        stack<int> st;
        int result = 0, sign = 1;
        for (char c : s) {
            if (isdigit(c)) {
                int num = c - '0';
                st.push(num * sign);
                result += num * sign;
            } else {
                switch (c) {
                    case '+':
                        result = st.top() + result;
                        st.pop();
                        break;
                    case '-':
                        result = st.top() - result;
                        st.pop();
                        break;
                    case '*':
                        result = st.top() * result;
                        st.pop();
                        break;
                    case '/':
                        if (st.empty()) {
                           throw invalid_operation();
                        }
                        result = st.top() / result;
                        st.pop();
                        break;
                }
            }
        }
    }
};

